using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=5e5+5;
int sum[MAXN],n,m; 
void fix(int x)
{
	for(int i=x;i<=n;i+=lowbit(i))
	{
		++sum[i];
	}
}
int get_sum(int x)
{
	int s=0;
	for(int i=x;i;i-=lowbit(i))
	{
		s+=sum[i];
	}
	return s;
}
signed main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
	n=read(),m=read();
	FOR(i,1,m)
	{
		int cmd=read(),x=read();
		if(cmd==1)
		{
            int y=read();
			fix(y+1); 
			fix(x); 
		}
		else
		{
			writeln(get_sum(x)&1);
		}
	}
    return false;
}
